import React, { useState } from 'react';

function App() {
  const [task, setTask] = useState('');
  const [tasks, setTasks] = useState([]);

  const addTask = () => {
    if (task.trim() !== '') {
      setTasks([...tasks, task]);
      setTask('');
    }
  };

  const deleteTask = (index) => {
    const updated = tasks.filter((_, i) => i !== index);
    setTasks(updated);
  };

  return (
    <div>
      <h2>Todo List</h2>
      <input
        type='text'
        value={task}
        placeholder='Enter task'
        onChange={(e) => setTask(e.target.value)}
      />
      <button onClick={addTask}>Add Task</button>
      <ul>
        {tasks.map((t, idx) => (
          <li key={idx}>
            {t}
            <button onClick={() => deleteTask(idx)} style={{marginLeft:'10px'}}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}
export default App;

